    `.trim();

    // Send summary to user
    await Telegram.sendMessage(chatId, summary);

    return { success: true, summary };
  } catch (error) {
    console.log('Error:', error.message);
    return { success: false, error: error.message };
  }
})();

function getWeatherDescription(code) {
  const descriptions = {
    0: 'Clear sky ☀️',
